import React from 'react'
import { monsterData } from '../game/monsterData'

export const MonsterDataPanel = () => {
  return (
    <details>
      <summary>Monster Data</summary>
      <table>
        <thead>
        <tr>
          <th>{`Monster Name`}</th>
          <th>{`Monster Health`}</th>
        </tr>
        </thead>
        <tbody>
        {monsterData.map(monster => {
          return (
            <tr key={monster.name}>
              <td>{monster.name}</td>
              <td>{monster.health}</td>
            </tr>
          )
        })}
        </tbody>
      </table>
    </details>
  )
}
