import React from 'react'
import { useSelector } from 'react-redux'

export const BuffPanel = () => {
  const state = useSelector(state => state)
  const buffList = state.playerBuff.buffList

  if (buffList.length <= 0) {
    return null
  }

  return (
    <fieldset>
      <legend>Buff</legend>
      <table>
        <thead>
        <tr>
          <th>{`Name`}</th>
          <th>{`Second`}</th>
        </tr>
        </thead>
        <tbody>
        {buffList.map(buff => {
          return (
            <tr key={buff.name}>
              <td>{buff.name}</td>
              <td>{buff.second}</td>
            </tr>
          )
        })}
        </tbody>
      </table>
    </fieldset>
  )
}
