import React from 'react'
import { useSelector, useStore } from 'react-redux'
import { buyShopItem } from '../game/gameLogic'

export const ShopPanel = () => {
  const store = useStore()
  const state = useSelector(state => state)

  const handleBuyClick = (shopItem) => {
    buyShopItem(store, shopItem)
  }

  return (
    <details>
      <summary>Shop</summary>
      <table>
        <thead>
        <tr>
          <th>{`Name`}</th>
          <th>{`Price`}</th>
          <th>{`Buy`}</th>
        </tr>
        </thead>
        <tbody>
        {state.shop.shopItemList.map(shopItem => {
          return (
            <tr key={shopItem.id}>
              <td>{shopItem.name}</td>
              <td>{shopItem.price}</td>
              <td>
                <button
                  onClick={() => handleBuyClick(shopItem)}
                  disabled={state.player.gold < shopItem.price}
                >
                  {`Buy`}
                </button>
              </td>
            </tr>
          )
        })}
        </tbody>
      </table>
    </details>
  )
}
