export const achievementReducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.achievementSuccess: {
      const achievement = state.find(item => item.id === action.data.achievementId)
      console.debug(`achievement ${achievement.name} success`)
      achievement.successDate = new Date()
      return state.map(item => item.id === action.data.id ? achievement : item)
    }
    default: {
      return state
    }
  }
}
