import React from 'react'
import { useDispatch, useSelector, useStore } from 'react-redux'
import { actionCreator } from './redux/actionCreator'
import { MonsterPanel } from './component/MonsterPanel'
import { LevelPanel } from './component/LevelPanel'
import { PlayerPanel } from './component/PlayerPanel'
import { MonsterDataPanel } from './component/MonsterDataPanel'
import { playerAttack } from './game/gameLogic'
import { GameInfoPanel } from './component/GameInfoPanel'
import { AchievementPanel } from './component/AchievementPanel'
import { ShopPanel } from './component/ShopPanel'
import { BuffPanel } from './component/BuffPanel'

function App () {
  const store = useStore()
  const dispatch = useDispatch()
  const state = useSelector(state => state)

  const handleUpgradeClick = () => {
    if (state.player.gold >= state.player.upgradeCost) {
      dispatch(actionCreator.upgrade())
    }
  }

  const handleAttackClick = () => {
    playerAttack(store)
  }

  return (
    <div>
      <h1>{`Idle Monster`}</h1>

      <MonsterPanel/>

      <LevelPanel/>

      <PlayerPanel/>

      <button
        onClick={handleUpgradeClick}
        disabled={state.player.gold < state.player.upgradeCost}
      >
        {`Upgrade`}
      </button>
      <button
        onClick={handleAttackClick}
      >
        {`Attack`}
      </button>

      <GameInfoPanel/>

      <BuffPanel/>

      <ShopPanel/>

      <AchievementPanel/>

      <MonsterDataPanel/>

      <footer>
        <span>{`Author: `}</span>
        <a
          href={`https://github.com/jerryshell`}
          target={`_blank`}
        >
          Jerry
        </a>
      </footer>

    </div>
  )
}

export default App
