import { actionType } from './actionType'

const initState = {
  // [ { name, second } ]
  buffList: [],
}

export const playerBuffReducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.update: {
      return handleUpdate(state)
    }
    case actionType.activeBuffDoubleCriticalHitChance: {
      return activeBuff(state, action, 'Double Critical Hit Chance')
    }
    case actionType.activeBuffDoubleGold: {
      return activeBuff(state, action, 'Double Gold')
    }
    default: {
      return state
    }
  }
}

const handleUpdate = (state) => {
  // reduce buff second
  let buffList = state.buffList.map(buff => {
    buff.second -= 1
    return buff
  })

  // filter second <= 0
  buffList = buffList.filter(buff => buff.second > 0)

  return {
    ...state,
    buffList
  }
}

const activeBuff = (state, action, buffName) => {
  let buffList = state.buffList

  // find buff by name
  let buff = buffList.find(buff => buff.name === buffName)

  // set already in buff list flag
  let alreadyInBuffList = true
  if (!buff) {
    alreadyInBuffList = false
    // init new buff
    buff = { name: buffName, second: 0 }
  }

  // increment second
  buff.second += action.data.second

  // update buff list
  if (alreadyInBuffList) {
    buffList = buffList.map(item => item.name === buffName ? buff : item)
  } else {
    buffList.push(buff)
  }

  return {
    ...state,
    buffList
  }
}
