import { monsterData } from './monsterData'
import { actionCreator } from '../redux/actionCreator'

export const onStateChange = (store) => {
  const state = store.getState()

  // MonsterKilledEvent
  if (state.currentMonster.health <= 0) {
    console.debug('handleMonsterKilledEvent')

    store.dispatch(actionCreator.handleMonsterKilledEvent(state.player.level))

    let incrementGoldAmount = Math.round(state.player.level * 1.33)
    const doubleGoldBuff = state.playerBuff.buffList.find(buff => buff.name === 'Double Gold')
    if (doubleGoldBuff) {
      incrementGoldAmount = incrementGoldAmount * 2
    }
    store.dispatch(actionCreator.incrementGold(incrementGoldAmount))

    store.dispatch(actionCreator.incrementKillAmount(1))
  }

  // LevelUpgradeEvent
  if (state.player.levelKillAmount >= state.player.levelKillAmountRequire) {
    console.debug('handleLevelUpgradeEvent')
    store.dispatch(actionCreator.handleLevelUpgradeEvent())
  }

  // achievement
  const notSuccessAchievementList = state.achievement.filter(achievement => achievement.successDate === null)

  notSuccessAchievementList.forEach(achievement => {
    const successFlagList = achievement.requireList.map(require => {
      const requireTypeCurrentValue = state[require.type]
      // console.debug('requireTypeCurrentValue', requireTypeCurrentValue)
      const requireTypeItemCurrentValue = requireTypeCurrentValue[require.itemName]
      // console.debug('requireTypeItemCurrentValue', requireTypeItemCurrentValue)

      return requireTypeItemCurrentValue >= require.amount
    })
    // console.debug('successFlagList', successFlagList)

    if (successFlagList.includes(false)) {
      return
    }

    // achievement success
    store.dispatch(actionCreator.achievementSuccess(achievement.id))
    achievement.rewardList.forEach(reward => {
      switch (reward.type) {
        case 'gold': {
          store.dispatch(actionCreator.incrementGold(reward.amount))
          break
        }
        default: {
          break
        }
      }
    })
  })
}

export const randomInt = (max) => {
  return Math.floor(Math.random() * Math.floor(max))
}

export const nextMonster = () => {
  const nextMonsterIndex = randomInt(monsterData.length)
  return { ...monsterData[nextMonsterIndex] }
}

export const setTimer = (store) => {
  const timer = setInterval(() => {
    // auto attack
    playerAttack(store)
    // update event
    store.dispatch(actionCreator.update({ store }))
  }, 1000)
  console.debug('timer', timer)
}

export const computePlayerCriticalHitChance = (state) => {
  let criticalHitChance = state.player.criticalHitChance
  const doubleCriticalHitChanceBuff = state.playerBuff.buffList.find(buff => buff.name === 'Double Critical Hit Chance')
  if (doubleCriticalHitChanceBuff) {
    return criticalHitChance * 2
  }
  return criticalHitChance
}

export const computePlayerDamage = (state) => {
  let criticalHitChance = computePlayerCriticalHitChance(state)
  const isCriticalHit = randomInt(100) + 1 <= criticalHitChance
  if (isCriticalHit) {
    console.debug('isCriticalHit')
    return state.player.damage * 2
  }
  return state.player.damage
}

export const playerAttack = (store) => {
  const state = store.getState()
  const playerDamage = computePlayerDamage(state)
  store.dispatch(actionCreator.damageMonster(playerDamage))
}

export const buyShopItem = (store, shopItem) => {
  console.debug('shopItem', shopItem)

  // validate player gold
  const playerGold = store.getState().player.gold
  console.debug('playerGold', playerGold)
  if (playerGold < shopItem.price) {
    console.debug('playerGold < shopItem.price')
    return
  }

  // reduce gold
  store.dispatch(actionCreator.reduceGold(shopItem.price))

  // buff
  switch (shopItem.id) {
    case '1': {
      // Double Critical Hit Chance 1 Minute
      store.dispatch(actionCreator.activeBuffDoubleCriticalHitChance(60))
      return
    }
    case '2': {
      // Double Gold 1 Minute
      store.dispatch(actionCreator.activeBuffDoubleGold(60))
      return
    }
    default: {
      return
    }
  }
}
