import { actionType } from './actionType'

const initState = {
  gameTime: 0,
  totalGold: 0,
  killAmount: 0,
}

export const gameInfoReducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.update: {
      const gameTime = state.gameTime + 1
      return {
        ...state,
        gameTime
      }
    }
    case actionType.incrementGold: {
      const totalGold = state.totalGold + action.data.amount
      return {
        ...state,
        totalGold
      }
    }
    case actionType.incrementKillAmount: {
      const killAmount = state.killAmount + action.data.amount
      return {
        ...state,
        killAmount
      }
    }
    default: {
      return state
    }
  }
}
